objectClass":"NSArray"},"text":"基础阅读"},"1":{"objectClass":"MindNode","ID":"60E47","children":{"0":{"objectClass":"MindNode","ID":"0D36H","text":"快速浏览全书，了解书的主题，架构全书，提出核心问题。"},"1":{"objectClass":"MindNode","ID":"PX818","text":"作用是为了帮助我们筛选这本书是否值得阅读，同时为接下来的分析阅读打下基础。"},"2":{"objectClass":"MindNode","ID":"L2Y86","text":"在这个层次中，我们关心的是，这本书在讲什么。"},"objectClass":"NSArray"},"text":"检视阅读"},"2":{"objectClass":"MindNode","ID":"Y67P4","children":{"0":{"objectClass":"MindNode","ID":"VK1HD","text":"目标是让我们能充分理解本书，与作者对话。"},"objectClass":"NSArray"},"text":"分析阅读"},"3":{"objectClass":"MindNode","ID":"7RI56","children":{"0":{"objectClass":"MindNode","ID":"1DVWV","text":"就相同的主题，阅读不同的书籍，找出其中关联与矛盾，倾听不同的作者的不同声音，从而对某个主题产生更加深刻的认识。"},"1":{"objectClass":"MindNode","ID":"K8QMF","text":"这个阶段，我们关注的不再是某一本书，而是一个具体的问题。"},"objectClass":"NSArray"},"text":"主题阅读"},"objectClass":"NSArray"},"text":"阅读的四个层次"},"1":{"objectClass":"MindNode","ID":"26D88","children":{"0":{"objectClass":"MindNode","ID":"37MI4","children":{"0":{"objectClass":"MindNode","ID":"QB88S","children":{"0":{"objectClass":"MindNode","ID":"7FF05","text":"相较其他学科，绝大多数计算机科学类书籍并不是以得出结论并且论证结论为核心，而偏重于阐述方法和解释原理。"},"objectClass":"NSArray"},"text":"单本书籍的信息量大"},"1":{"objectClass":"MindNode","ID":"K73FO","children":{"0":{"objectClass":"MindNode","ID":"68D7Y","text":"计算机科学是一门实用性的学科。这里的实用性可以理解为，计算机科学诞生的目的就是为了解决实际问题。因此，几乎所有的计算机科学书籍，都是以指导实践为目标而作。"},"objectClass":"NSArray"},"text":"注重实践"},"2":{"objectClass":"MindNode","ID":"R2XW6","children":{"0":{"objectClass":"MindNode","ID":"A97I7","text":"有些技术很快地火爆起来，又很快地消亡，所以有些书也就跟着很快地淹没在时代的进程中。"},"objectClass":"NSArray"},"text":"更新速度快"},"3":{"objectClass":"MindNode","ID":"CL589","children":{"0":{"objectClass":"MindNode","ID":"GEB6Q","text":"计算机科学对自己有着过分清晰的划分，不同的技术之间往往边界清晰。"},"1":{"objectClass":"MindNode","ID":"3UV70","text":"由于领域划分细致，相同领域的书籍，多数时候往往论述的是同样的主题。"},"objectClass":"NSArray"},"text":"分类细致但同质度高"},"objectClass":"NSArray"},"text":"计算机科学类书籍，较其他类型图书有着其独特性："},"1":{"objectClass":"MindNode","ID":"74KC5","children":{"0":{"objectClass":"MindNode","ID":"HNO82","children":{"0":{"objectClass":"MindNode","ID":"QNPU2","text":"这是一种低效的读书方式。当读到中落时，你会因为没有全局概念，而迷失在各种细节中，以至于完全失去了阅读的方向和目标。"},"objectClass":"NSArray"},"text":"通读全书"},"1":{"objectClass":"MindNode","ID":"EO657","children":{"0":{"objectClass":"MindNode","ID":"K9D1W","text":"序言以简短精炼的语言，为你分解了整本书的架构，帮助你把握系统的整体。"},"objectClass":"NSArray"},"text":"跳过序言"},"2":{"objectClass":"MindNode","ID":"8OF07","children":{"0":{"objectClass":"MindNode","ID":"TXYIV","text":"脱离了实践，往往就不能完全理解书中所述的理论和方法，过目就忘，纸上谈兵。"},"objectClass":"NSArray"},"text":"脱离实践"},"3":{"objectClass":"MindNode","ID":"J7YQU","children":{"0":{"objectClass":"MindNode","ID":"35166","text":"封装在计算机的世界中是一个非常重要的概念。计算机的发展史，总的来说就是一部封装史：将底层不断包装，提供简单的调用方式，由此不断的扩展计算机的边界和能力。"},"1":{"objectClass":"MindNode","ID":"079H0","text":"新的技术层出不穷，而他们的很多所依赖的环境和系统，从设计之初就没有发生过质的变化。"},"2":{"objectClass":"MindNode","ID":"W2FW6","text":"在追逐新的技术之前，深入了解他们所在的系统；在学习新的算法之前，掌握好其基础的数学原理。"},"3":{"objectClass":"MindNode","ID":"HL4IW","text":"只有牢固的基础才能支撑足够结实的上层建筑。"},"objectClass":"NSArray"},"text":"忽视基础"},"objectClass":"NSArray"},"text":"阅读计算机科学书籍的误区","remark":"绝大多数读者的错误意识在于把所有的书籍都认为是层层推进的论述过程。这样的阅读经验一旦沿用在计算机科学类书籍中，就会感觉举步维艰。","remarkDisplay":true},"2":{"objectClass":"MindNode","ID":"CDNGI","children":{"0":{"objectClass":"MindNode","ID":"L1103","text":"将整本书当做一个系统，从整体到局部，层层递进，逐步剖析。"},"1":{"objectClass":"MindNode","ID":"U7798","children":{"0":{"objectClass":"MindNode","ID":"0888W","text":"当你拿到一本计算机科学书籍，第一步就应该快速浏览序言和目录，然后用检视阅读的方式整理出整本书的大纲。"},"1":{"objectClass":"MindNode","ID":"I73Q9","text":"这样，你对这本书是介绍理论还是关注实践，所属什么分类，哪些问题是本书将会讨论，而哪些问题是不被详细讨论的，这些信息你都会有整体上的认知。"},"2":{"objectClass":"MindNode","ID":"258T1","text":"这时，你就可以很轻松地判断，这本书值不值的阅读，哪些内容是你已经熟知的，哪些内容是你关注的重点，这样做阅读的效率将会大大的提高。"},"objectClass":"NSArray"},"text":"检视阅读"},"2":{"objectClass":"MindNode","ID":"9J546","children":{"0":{"objectClass":"MindNode","ID":"52ZD9","text":"当你了解了整本书的全貌，一般而言，你会发现，有些章节你已经熟悉，有些章节你全然不知。这时就要对这些章节进行分析阅读。"},"1":{"objectClass":"MindNode","ID":"43E9L","text":"有时，你在阅读的过程中，会发现阅读的兴趣在下降。信息量愈大，阅读的动力愈弱，最后你就迷失在信息的汪洋之中。"},"2":{"objectClass":"MindNode","ID":"JTP3S","text":"我们应该如何避免这样的信息疲劳呢？答案就是去掉冗余的干扰信息。"},"objectClass":"NSArray"},"text":"提取问题"},"3":{"objectClass":"MindNode","ID":"368AM","children":{"0":{"objectClass":"MindNode","ID":"1W56D","children":{"0":{"objectClass":"MindNode","ID":"2GQL5","text":"毫不夸张的说，计算机科学类的书籍生来就是供人反复翻阅的。"},"objectClass":"NSArray"},"text":"一本经典优秀的计算机科学书籍，值得你反复的阅读。"},"1":{"objectClass":"MindNode","ID":"WT93W","text":"因为此类书籍存在大量信息，而这些信息并没有必要占据我们大脑有限的记忆存储空间。"},"2":{"objectClass":"MindNode","ID":"NO2M4","text":"我们要做的就是认真做好第一条建议，当我们需要使用这些书籍解决问题的时候，能第一时间在其中找到我们需要的信息。"},"objectClass":"NSArray"},"text":"持续重读"},"4":{"objectClass":"MindNode","ID":"R7CA1","children":{"0":{"objectClass":"MindNode","ID":"7J1R5","text":"作为阅读爱好者，谁能说自己没读过几本烂书呢。"},"1":{"objectClass":"MindNode","ID":"DS31J","text":"信息重复（抄袭），结构混乱，论证不清晰（作者对某个技术一知半解）等等，都是烂书的特征。"},"objectClass":"NSArray"},"text":"鉴别烂书"},"objectClass":"NSArray"},"text":"阅读计算机科学书籍的建议"},"objectClass":"NSArray"},"text":"如何阅读计算机科学书籍？"},"objectClass":"NSArray"},"text":"如何阅读计算机科学书籍？","remark":"https://mp.weixin.qq.com/s/hv55oY3qvyy7UM9nBeaZ8Q\n来源于莫提默·J·艾德勒和查尔斯·范多伦的著作\n《如何阅读一本书（How To Read A Book）》","remarkDisplay":true},"objectClass":"NSArray"},"text":"人生哲理与规划","remark":"记录一些人生哲理，更好地指导未来的生活。","remarkDisplay":true},"ID":"63WC6","style":100}